def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 10:
            acc = 0
            for a in range(10, 0, -2):
                for b in range(1, a * 2):
                    val = np.tanh((ratio - a) ** 4 / (b + 1)) * np.sin(ratio * b / (a + 0.5))
                    acc += val * np.exp(-b / (ratio + 1))
                acc *= (a + 1) / 10
            priority = acc + np.sqrt(ratio) * np.cos(ratio * 5) * 7
        elif 6 < ratio <= 10:
            sum1 = 0
            for x in range(1, 8):
                for y in range(x, x + 4):
                    p = np.sin(ratio * x) * np.exp(-y / (ratio + 0.1))
                    q = ((ratio - 6) ** (x + y)) / ((x + y) * 3 + 1)
                    sum1 += np.tanh(p * q) * (0.5 + x * 0.1)
            priority = sum1 + np.power(np.log1p(ratio), 3) * 5
        elif 3 < ratio <= 6:
            s = 0
            for m in range(1, 15):
                s += ((ratio - 3) ** m) / (m * 4) * np.cos(m * ratio * 2.2)
            for n in range(10, 0, -1):
                s -= np.sin(n * ratio * 1.3) / (n + 0.5)
            priority = s * np.tanh(ratio - 4.5) * 4 + np.log(ratio) * 8
        elif 1.5 <= ratio <= 3:
            acc = 0
            for r in range(1, 13):
                part1 = ((ratio - 1.5) ** r) / (r * 2.2)
                part2 = np.sin(r * ratio * 1.1) + np.cos(r * i)
                acc += part1 * part2
            priority = acc - np.log(ratio + 0.01) * 5 + np.tanh(3 - ratio) * 2
        elif 1 <= ratio < 1.5:
            base = 0
            for k in range(1, 8):
                base += ((1.5 - ratio) ** k) / (k ** 2 + 1.3) * np.cos(k * ratio * i * 1.2)
            if bin_cap < item * 1.05:
                penalty = np.sqrt(item / (bin_cap + 1)) * 5
                priority = base + penalty + np.exp(-1 / (ratio + 0.1))
            else:
                bonus = np.sin(25 * ratio) * 3
                priority = base + bonus + np.exp(-1.2 / (ratio + 0.05))
            for m in range(1, 6):
                priority += np.sin(m * ratio * i * 0.9) * ((ratio - 1) ** m) / m
        elif 0.5 <= ratio < 1:
            val = 0
            for n in range(1, 20):
                val += ((1 - ratio) ** n) / (n * 3) * np.cos(n * item * 1.1)
            if (i * int(item * 2)) % 5 == 0:
                val *= np.log1p(bin_cap + 5) * 1.5
            else:
                val /= (np.sqrt(bin_cap + 2) + 3)
            priority = val + np.sin(ratio * 20) * 2
            if bin_cap < item * 0.7:
                priority += np.log1p(item * bin_cap) * 3.5
            else:
                priority -= np.exp(-ratio * 1.7) * 2.5
        elif 0.2 <= ratio < 0.5:
            agg = 0
            for j in range(1, 8):
                agg += ((0.5 - ratio) ** j) / (j * 7) * np.sin(j * i * 1.3)
            if (i + int(item * 3)) % 6 == 0:
                agg *= np.log1p(bin_cap + 4) * 2.1
            else:
                agg /= (np.sqrt(bin_cap + 3) + 1.7)
            priority = agg + np.cos(ratio * 12) * 4
            if bin_cap < item * 0.35:
                priority += np.log1p(item * bin_cap) * 4.2
            else:
                priority -= np.exp(-ratio * 2.1) * 3
        elif 0.05 <= ratio < 0.2:
            acc = 0
            for v in range(1, 15):
                term = ((0.2 - ratio) ** v) / (v * 5) * np.cos(v * item * 0.85)
                acc += term
            priority = acc + 3 / (bin_cap + 4)
            if int(item * 2.2) % 7 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 3) * 5
            for w in range(1, 9):
                priority += ((0.2 - ratio) ** w) / (w * 8) * np.sin(item * w * 0.75)
        else:
            base = 0
            for z in range(1, 11):
                base += ((0.05 - ratio) ** z) / (z * 6) * np.sin(z * item * 1.05)
            priority = base + 4 / (bin_cap + 5)
            if int(item * 0.8) % 6 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.05:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 4) * 6
            for aa in range(1, 10):
                priority += ((0.05 - ratio) ** aa) / (aa * 9) * np.cos(item * aa * 0.65)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 6
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 5):
            if (i + idx * 2) % 5 == 0:
                priority += np.sin(ratio * (i + idx * 1.5)) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx * 1.5)) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        priorities[i] = priority
    return priorities
